import React from "react";
import styled from "styled-components";

// TODO: Account for when the user has manually colored everything, then we want to switch the button to back to gray

const ColorButton = (props) => {
  return (
    <StyledButton onClick={(e) => props.clickHandler(e)}>
      Click me or the spacebar for random color scheme!
    </StyledButton>
  );
};

export default ColorButton;

const StyledButton = styled.button`
  position: fixed;
  top: 0px;
  left: 0px;
  z-index: 10;

  width: 12rem;

  margin: 1rem 1rem 1rem 1rem;

  background: white; // TODO: Background switch from grayscale (see images dir) to color gradient (make urself)

  font-size: 1.5rem;

  border-radius: 1rem;

  cursor: pointer;
  border: none;
  outline: none;
  text-decoration: none;

  transition: transform 0.1s linear;
  :hover {
    transition: transform 0.1s linear;
    transform: scale(1.1);
  }
`;
