import React from "react";
import styled from "styled-components";
import emailjs from "emailjs-com";

import Panel from "./panel";
import Button from "./button";

class ContactPanel extends React.Component {
  constructor(props) {
    super(props);
    this.state = { submitted: false, error: false };
  }

  handleSubmit = (e) => {
    e.preventDefault();
    console.log(process.env.REACT_APP_EMAILJS_USER_ID);
    emailjs
      .sendForm(
        process.env.REACT_APP_EMAILJS_SERVICE_ID,
        process.env.REACT_APP_EMAILJS_TEMPLATE_ID,
        e.target,
        process.env.REACT_APP_EMAILJS_USER_ID
      )
      .then(
        (result) => {
          console.log(result.text);
          this.setState({ submitted: true });
          this.setState({ error: false });
        },
        (error) => {
          console.log(error.text);
          this.setState({ submitted: false });
          this.setState({ error: true });
        }
      );
    e.target.reset();
  };

  render() {
    return (
      <Panel color={this.props.colors.panel}>
        <TitleRow>
          <Title color={this.props.colors.heading}>Contact Me</Title>
        </TitleRow>
        <BodyContainer>
          <Form onSubmit={this.handleSubmit}>
            <SenderInfoRow>
              <SenderInfoInput
                type="text"
                placeholder="Your name"
                name="name"
                required
              />
              <SenderInfoInput
                type="email"
                placeholder="Your email"
                name="email"
                required
              />
            </SenderInfoRow>
            <MessageRow>
              <MessageInput
                id="contactMessage"
                type="text"
                placeholder="Want to connect, collaborate, or critique? Send me a message!"
                name="message"
                required
              />
            </MessageRow>
            <SubmitRow>
              {this.state.submitted ? (
                <SubmitResponse color={this.props.colors.button_text}>
                  Submitted!
                </SubmitResponse>
              ) : this.state.error ? (
                <SubmitResponse color={this.props.colors.button_text}>
                  Oops, something went wrong. Please email me at
                  ezduanmu@gmail.com instead!
                </SubmitResponse>
              ) : null}
              <Button
                type="submit"
                value="Submit"
                backgroundColor={this.props.colors.panel}
                borderColor={this.props.colors.button_border}
                textColor={this.props.colors.button_text}
                hoverBackgroundColor={this.props.colors.main}
              >
                Submit
              </Button>
            </SubmitRow>
          </Form>
        </BodyContainer>
      </Panel>
    );
  }
}

export default ContactPanel;

